package com.apex.coach.ui\n\nimport androidx.compose.animation.core.Animatable\nimport androidx.compose.animation.core.tween\nimport androidx.compose.foundation.background\nimport androidx.compose.foundation.clickable\nimport androidx.compose.foundation.layout.*\nimport androidx.compose.foundation.rememberScrollState\nimport androidx.compose.foundation.shape.CircleShape\nimport androidx.compose.foundation.shape.RoundedCornerShape\nimport androidx.compose.material.icons.Icons\nimport androidx.compose.material.icons.filled.Add\nimport androidx.compose.material.icons.filled.DateRange\nimport androidx.compose.material.icons.filled.Favorite\nimport androidx.compose.material.icons.filled.Home\nimport androidx.compose.material.icons.filled.Person\nimport androidx.compose.material.icons.filled.Settings\nimport androidx.compose.material3.*\nimport androidx.compose.runtime.*\nimport androidx.compose.ui.Alignment\nimport androidx.compose.ui.Modifier\nimport androidx.compose.ui.draw.clip\nimport androidx.compose.ui.graphics.Color\nimport androidx.compose.ui.res.stringResource\nimport androidx.compose.ui.text.font.FontWeight\nimport androidx.compose.ui.text.style.TextAlign\nimport androidx.compose.ui.unit.dp\nimport androidx.compose.ui.unit.sp\nimport androidx.hilt.navigation.compose.hiltViewModel\nimport androidx.lifecycle.compose.collectAsStateWithLifecycle\nimport com.apex.coach.R\nimport com.apex.coach.domain.model.WorkoutMode\nimport com.apex.coach.ui.components.ApexBottomNavigation\nimport kotlinx.coroutines.launch\n\n@OptIn(ExperimentalMaterial3Api::class)\n@Composable\nfun DashboardScreen(\n    onNavigateToSession: (String) -> Unit,\n    onNavigateToLibrary: () -> Unit,\n    onNavigateToAnalytics: () -> Unit,\n    onNavigateToSettings: () -> Unit,\n    viewModel: DashboardViewModel = hiltViewModel()\n) {\n    val state by viewModel.state.collectAsStateWithLifecycle()\n    val scrollState = rememberScrollState()\n    \n    Scaffold(\n        bottomBar = {\n            ApexBottomNavigation(\n                currentRoute = \"dashboard\",\n                onNavigateToDashboard = { /* Already on dashboard */ },\n                onNavigateToLibrary = onNavigateToLibrary,\n                onNavigateToAnalytics = onNavigateToAnalytics,\n                onNavigateToSettings = onNavigateToSettings\n            )\n        }\n    ) {\ padding ->\n        Column(\n            modifier = Modifier\n                .fillMaxSize()\n                .padding(padding)\n                .verticalScroll(scrollState)\n                .padding(16.dp),\n            verticalArrangement = Arrangement.spacedBy(24.dp)\n        ) {\n            // Header\n            Text(\n                text = stringResource(R.string.dashboard_title),\n                style = MaterialTheme.typography.headlineLarge,\n                fontWeight = FontWeight.Bold\n            )\n            \n            // Apex Score Gauge\n            ApexScoreGauge(\n                score = state.apexScore,\n                isLoading = state.isLoadingScore,\n                onRefresh = viewModel::refreshScore\n            )\n            \n            // Mode Selector (Elastic Programming)\n            ModeSelector(\n                selectedMode = state.selectedMode,\n                recommendedMode = state.apexScore?.mode,\n                onModeSelected = viewModel::onModeSelected,\n                enabled = !state.isLoadingScore\n            )\n            \n            // Streak Visualizer (14-dot row)\n            StreakVisualizer(\n                streakDays = state.streakDays,\n                last14Days = state.last14Days,\n                isFrozen = state.isStreakFrozen,\n                onStreakInfoClick = { /* Show streak info dialog */ }\n            )\n            \n            // Biometrics Row\n            BiometricsRow(\n                hrv = state.hrv,\n                sleepHours = state.sleepHours,\n                rhr = state.rhr,\n                isStale = state.isDataStale,\n                lastSyncTime = state.lastSyncTime,\n                onSyncClick = viewModel::syncHealthData\n            )\n            \n            // Today's Workout Card\n            if (state.todayWorkout != null) {\n                TodayWorkoutCard(\n                    workout = state.todayWorkout!!,\n                    mode = state.selectedMode,\n                    onStartClick = { onNavigateToSession(state.todayWorkout!!.id) }\n                )\n            } else {\n                EmptyWorkoutCard(\n                    onBrowsePrograms = onNavigateToLibrary\n                )\n            }\n            \n            // Health Connect Warning\n            if (state.healthConnectUnavailable) {\n                HealthConnectBanner(\n                    onInstallClick = viewModel::openHealthConnectInstall\n                )\n            }\n            \n            // Permission Denied Fallback\n            if (state.permissionsDenied) {\n                EnergySliderCard(\n                    energyLevel = state.manualEnergyLevel,\n                    onEnergyChange = viewModel::onManualEnergyChange\n                )\n            }\n        }\n    }\n}\n\n@Composable\nfun ApexScoreGauge(\n    score: com.apex.coach.domain.model.ApexScore?,\n    isLoading: Boolean,\n    onRefresh: () -> Unit,\n    modifier: Modifier = Modifier\n) {\n    Card(\n        modifier = modifier.fillMaxWidth(),\n        colors = CardDefaults.cardColors(\n            containerColor = MaterialTheme.colorScheme.surfaceVariant\n        ),\n        shape = RoundedCornerShape(24.dp)\n    ) {\n        Column(\n            modifier = Modifier\n                .fillMaxWidth()\n                .padding(24.dp),\n            horizontalAlignment = Alignment.CenterHorizontally\n        ) {\n            Text(\n                text = stringResource(R.string.apex_score_title),\n                style = MaterialTheme.typography.labelLarge,\n                color = MaterialTheme.colorScheme.onSurfaceVariant\n            )\n            \n            Spacer(modifier = Modifier.height(16.dp))\n            \n            if (isLoading) {\n                CircularProgressIndicator(modifier = Modifier.size(120.dp))\n            } else if (score != null) {\n                // Animated Gauge\n                val animatedValue = remember { Animatable(0f) }\n                \n                LaunchedEffect(score.value) {\n                    animatedValue.animateTo(\n                        targetValue = score.value.toFloat(),\n                        animationSpec = tween(durationMillis = 1500)\n                    )\n                }\n                \n                Box(\n                    modifier = Modifier.size(200.dp),\n                    contentAlignment = Alignment.Center\n                ) {\n                    // Background arc\n                    CircularProgressIndicator(\n                        progress = 1f,\n                        modifier = Modifier.fillMaxSize(),\n                        color = MaterialTheme.colorScheme.surface,\n                        strokeWidth = 20.dp,\n                        trackColor = MaterialTheme.colorScheme.surface\n                    )\n                    \n                    // Value arc\n                    CircularProgressIndicator(\n                        progress = animatedValue.value / 100f,\n                        modifier = Modifier.fillMaxSize(),\n                        color = when (score.mode) {\n                            WorkoutMode.FULL -> Color(0xFF4CAF50)\n                            WorkoutMode.EXPRESS -> Color(0xFFFFC107)\n                            WorkoutMode.REHAB -> Color(0xFF2196F3)\n                        },\n                        strokeWidth = 20.dp\n                    )\n                    \n                    Column(horizontalAlignment = Alignment.CenterHorizontally) {\n                        Text(\n                            text = \"${animatedValue.value.toInt()}\",\n                            style = MaterialTheme.typography.displayLarge,\n                            fontWeight = FontWeight.Bold\n                        )\n                        Text(\n                            text = \"/100\",\n                            style = MaterialTheme.typography.titleMedium,\n                            color = MaterialTheme.colorScheme.onSurfaceVariant\n                        )\n                    }\n                }\n                \n                Spacer(modifier = Modifier.height(16.dp))\n                \n                // Mode Label\n                Surface(\n                    color = when (score.mode) {\n                        WorkoutMode.FULL -> Color(0xFF4CAF50).copy(alpha = 0.2f)\n                        WorkoutMode.EXPRESS -> Color(0xFFFFC107).copy(alpha = 0.2f)\n                        WorkoutMode.REHAB -> Color(0xFF2196F3).copy(alpha = 0.2f)\n                    },\n                    shape = RoundedCornerShape(16.dp)\n                ) {\n                    Text(\n                        text = stringResource(\n                            when (score.mode) {\n                                WorkoutMode.FULL -> R.string.mode_full_label\n                                WorkoutMode.EXPRESS -> R.string.mode_express_label\n                                WorkoutMode.REHAB -> R.string.rehab_mode_label\n                            }\n                        ),\n                        modifier = Modifier.padding(horizontal = 16.dp, vertical = 8.dp),\n                        style = MaterialTheme.typography.titleMedium,\n                        fontWeight = FontWeight.SemiBold,\n                        color = when (score.mode) {\n                            WorkoutMode.FULL -> Color(0xFF4CAF50)\n                            WorkoutMode.EXPRESS -> Color(0xFFFFC107)\n                            WorkoutMode.REHAB -> Color(0xFF2196F3)\n                        }\n                    )\n                }\n            } else {\n                Text(\n                    text = stringResource(R.string.empty_dashboard),\n                    style = MaterialTheme.typography.bodyLarge,\n                    textAlign = TextAlign.Center\n                )\n            }\n        }\n    }\n}\n\n@Composable\nfun ModeSelector(\n    selectedMode: WorkoutMode,\n    recommendedMode: WorkoutMode?,\n    onModeSelected: (WorkoutMode) -> Unit,\n    enabled: Boolean\n) {\n    Column {\n        Text(\n            text = stringResource(R.string.mode_selector_title),\n            style = MaterialTheme.typography.titleMedium,\n            fontWeight = FontWeight.SemiBold\n        )\n        \n        Spacer(modifier = Modifier.height(8.dp))\n        \n        Row(\n            modifier = Modifier.fillMaxWidth(),\n            horizontalArrangement = Arrangement.spacedBy(8.dp)\n        ) {\n            WorkoutMode.values().forEach { mode ->\n                val isRecommended = mode == recommendedMode\n                val isSelected = mode == selectedMode\n                \n                FilterChip(\n                    selected = isSelected,\n                    onClick = { if (enabled) onModeSelected(mode) },\n                    label = { \n                        Text(\n                            text = stringResource(\n                                when (mode) {\n                                    WorkoutMode.FULL -> R.string.mode_full_chip\n                                    WorkoutMode.EXPRESS -> R.string.mode_express_chip\n                                    WorkoutMode.REHAB -> R.string.mode_rehab_chip\n                                }\n                            )\n                        )\n                    },\n                    leadingIcon = if (isRecommended) {\n                        { \n                            Icon(\n                                imageVector = Icons.Default.Favorite,\n                                contentDescription = \"Recommended\",\n                                modifier = Modifier.size(16.dp)\n                            )\n                        }\n                    } else null,\n                    enabled = enabled,\n                    colors = FilterChipDefaults.filterChipColors(\n                        selectedContainerColor = when (mode) {\n                            WorkoutMode.FULL -> Color(0xFF4CAF50)\n                            WorkoutMode.EXPRESS -> Color(0xFFFFC107)\n                            WorkoutMode.REHAB -> Color(0xFF2196F3)\n                        }.copy(alpha = 0.2f)\n                    )\n                )\n            }\n        }\n        \n        if (selectedMode != recommendedMode) {\n            Text(\n                text = stringResource(R.string.mode_override_notice),\n                style = MaterialTheme.typography.bodySmall,\n                color = MaterialTheme.colorScheme.onSurfaceVariant,\n                modifier = Modifier.padding(top = 4.dp)\n            )\n        }\n    }\n}\n\n@Composable\nfun StreakVisualizer(\n    streakDays: Int,\n    last14Days: List<com.apex.coach.domain.usecase.CalculateStreakUseCase.DayStatus>,\n    isFrozen: Boolean,\n    onStreakInfoClick: () -> Unit\n) {\n    Card(\n        modifier = Modifier.fillMaxWidth(),\n        colors = CardDefaults.cardColors(\n            containerColor = MaterialTheme.colorScheme.surface\n        )\n    ) {\n        Column(\n            modifier = Modifier.padding(16.dp)\n        ) {\n            Row(\n                modifier = Modifier.fillMaxWidth(),\n                horizontalArrangement = Arrangement.SpaceBetween,\n                verticalAlignment = Alignment.CenterVertically\n            ) {\n                Column {\n                    Text(\n                        text = \"$streakDays\",\n                        style = MaterialTheme.typography.displayMedium,\n                        fontWeight = FontWeight.Bold\n                    )\n                    Text(\n                        text = stringResource(R.string.streak_label),\n                        style = MaterialTheme.typography.bodyMedium\n                    )\n                }\n                \n                if (isFrozen) {\n                    Surface(\n                        color = MaterialTheme.colorScheme.primaryContainer,\n                        shape = RoundedCornerShape(8.dp)\n                    ) {\n                        Text(\n                            text = stringResource(R.string.streak_freeze_label),\n                            modifier = Modifier.padding(horizontal = 12.dp, vertical = 6.dp),\n                            style = MaterialTheme.typography.labelMedium\n                        )\n                    }\n                }\n            }\n            \n            Spacer(modifier = Modifier.height(12.dp))\n            \n            // 14-dot row\n            Row(\n                modifier = Modifier.fillMaxWidth(),\n                horizontalArrangement = Arrangement.SpaceBetween\n            ) {\n                last14Days.takeLast(14).forEach { day ->\n                    val color = when (day.status) {\n                        com.apex.coach.data.local.entity.StreakStatus.COMPLETED -> \n                            MaterialTheme.colorScheme.primary\n                        com.apex.coach.data.local.entity.StreakStatus.MISSED_FROZEN -> \n                            MaterialTheme.colorScheme.tertiary\n                        com.apex.coach.data.local.entity.StreakStatus.MISSED_BROKEN -> \n                            MaterialTheme.colorScheme.error.copy(alpha = 0.5f)\n                        else -> MaterialTheme.colorScheme.surfaceVariant\n                    }\n                    \n                    Box(\n                        modifier = Modifier\n                            .size(20.dp)\n                            .clip(CircleShape)\n                            .background(color)\n                            .then(if (day.isToday) Modifier.padding(2.dp) else Modifier)\n                    )\n                }\n            }\n        }\n    }\n}\n\n@Composable\nfun BiometricsRow(\n    hrv: Double?,\n    sleepHours: Double?,\n    rhr: Double?,\n    isStale: Boolean,\n    lastSyncTime: String?,\n    onSyncClick: () -> Unit\n) {\n    Card(\n        modifier = Modifier.fillMaxWidth()\n    ) {\n        Column(modifier = Modifier.padding(16.dp)) {\n            Row(\n                modifier = Modifier.fillMaxWidth(),\n                horizontalArrangement = Arrangement.SpaceBetween,\n                verticalAlignment = Alignment.CenterVertically\n            ) {\n                Text(\n                    text = stringResource(R.string.biometrics_title),\n                    style = MaterialTheme.typography.titleMedium\n                )\n                \n                if (isStale) {\n                    TextButton(onClick = onSyncClick) {\n                        Text(stringResource(R.string.sync_button))\n                    }\n                }\n            }\n            \n            Spacer(modifier = Modifier.height(8.dp))\n            \n            Row(\n                modifier = Modifier.fillMaxWidth(),\n                horizontalArrangement = Arrangement.SpaceEvenly\n            ) {\n                BiometricItem(\n                    label = stringResource(R.string.hrv_label),\n                    value = hrv?.let { \"${it.toInt()} ms\" } ?: \"--\",\n                    icon = Icons.Default.Favorite\n                )\n                \n                BiometricItem(\n                    label = stringResource(R.string.sleep_label),\n                    value = sleepHours?.let { String.format(\"%.1f h\", it) } ?: \"--\",\n                    icon = Icons.Default.DateRange\n                )\n                \n                BiometricItem(\n                    label = stringResource(R.string.rhr_label),\n                    value = rhr?.let { \"${it.toInt()} bpm\" } ?: \"--\",\n                    icon = Icons.Default.Favorite\n                )\n            }\n            \n            if (isStale) {\n                Spacer(modifier = Modifier.height(8.dp))\n                Text(\n                    text = stringResource(R.string.data_stale_warning),\n                    style = MaterialTheme.typography.bodySmall,\n                    color = MaterialTheme.colorScheme.error\n                )\n            }\n        }\n    }\n}\n\n@Composable\nfun BiometricItem(\n    label: String,\n    value: String,\n    icon: androidx.compose.ui.graphics.vector.ImageVector\n) {\n    Column(horizontalAlignment = Alignment.CenterHorizontally) {\n        Icon(\n            imageVector = icon,\n            contentDescription = label,\n            tint = MaterialTheme.colorScheme.primary\n        )\n        Spacer(modifier = Modifier.height(4.dp))\n        Text(\n            text = value,\n            style = MaterialTheme.typography.titleMedium,\n            fontWeight = FontWeight.Bold\n        )\n        Text(\n            text = label,\n            style = MaterialTheme.typography.bodySmall,\n            color = MaterialTheme.colorScheme.onSurfaceVariant\n        )\n    }\n}\n\n@Composable\nfun TodayWorkoutCard(\n    workout: com.apex.coach.domain.model.Workout,\n    mode: WorkoutMode,\n    onStartClick: () -> Unit\n) {\n    Card(\n        modifier = Modifier.fillMaxWidth(),\n        colors = CardDefaults.cardColors(\n            containerColor = MaterialTheme.colorScheme.primaryContainer\n        )\n    ) {\n        Column(\n            modifier = Modifier.padding(20.dp)\n        ) {\n            Text(\n                text = workout.name,\n                style = MaterialTheme.typography.headlineSmall,\n                fontWeight = FontWeight.Bold\n            )\n            \n            Text(\n                text = stringResource(R.string.mode_label, \n                    stringResource(\n                        when (mode) {\n                            WorkoutMode.FULL -> R.string.mode_full_label\n                            WorkoutMode.EXPRESS -> R.string.mode_express_label\n                            WorkoutMode.REHAB -> R.string.rehab_mode_label\n                        }\n                    )\n                ),\n                style = MaterialTheme.typography.bodyMedium,\n                modifier = Modifier.padding(vertical = 4.dp)\n            )\n            \n            Spacer(modifier = Modifier.height(12.dp))\n            \n            Button(\n                onClick = onStartClick,\n                modifier = Modifier.fillMaxWidth(),\n                colors = ButtonDefaults.buttonColors(\n                    containerColor = MaterialTheme.colorScheme.primary\n                )\n            ) {\n                Text(\n                    text = stringResource(\n                        when (mode) {\n                            WorkoutMode.FULL -> R.string.start_full_workout\n                            WorkoutMode.EXPRESS -> R.string.start_express_workout\n                            WorkoutMode.REHAB -> R.string.start_rehab_workout\n                        }\n                    ),\n                    modifier = Modifier.padding(vertical = 4.dp)\n                )\n            }\n        }\n    }\n}\n\n@Composable\nfun EmptyWorkoutCard(\n    onBrowsePrograms: () -> Unit\n) {\n    Card(\n        modifier = Modifier.fillMaxWidth()\n    ) {\n        Column(\n            modifier = Modifier\n                .fillMaxWidth()\n                .padding(20.dp),\n            horizontalAlignment = Alignment.CenterHorizontally\n        ) {\n            Text(\n                text = stringResource(R.string.no_active_program),\n                style = MaterialTheme.typography.titleMedium\n            )\n            \n            Spacer(modifier = Modifier.height(8.dp))\n            \n            Text(\n                text = stringResource(R.string.browse_programs_prompt),\n                style = MaterialTheme.typography.bodyMedium,\n                textAlign = TextAlign.Center,\n                color = MaterialTheme.colorScheme.onSurfaceVariant\n            )\n            \n            Spacer(modifier = Modifier.height(12.dp))\n            \n            OutlinedButton(\n                onClick = onBrowsePrograms,\n                modifier = Modifier.fillMaxWidth()\n            ) {\n                Text(stringResource(R.string.browse_programs_button))\n            }\n        }\n    }\n}\n\n@Composable\nfun HealthConnectBanner(\n    onInstallClick: () -> Unit\n) {\n    Surface(\n        color = MaterialTheme.colorScheme.errorContainer,\n        shape = RoundedCornerShape(12.dp)\n    ) {\n        Row(\n            modifier = Modifier\n                .fillMaxWidth()\n                .padding(16.dp),\n            verticalAlignment = Alignment.CenterVertically\n        ) {\n            Column(modifier = Modifier.weight(1f)) {\n                Text(\n                    text = stringResource(R.string.health_connect_missing_title),\n                    style = MaterialTheme.typography.titleSmall,\n                    fontWeight = FontWeight.Bold\n                )\n                Text(\n                    text = stringResource(R.string.health_connect_missing_body),\n                    style = MaterialTheme.typography.bodySmall\n                )\n            }\n            \n            Button(onClick = onInstallClick) {\n                Text(stringResource(R.string.install_button))\n            }\n        }\n    }\n}\n\n@Composable\nfun EnergySliderCard(\n    energyLevel: Int,\n    onEnergyChange: (Int) -> Unit\n) {\n    Card(\n        modifier = Modifier.fillMaxWidth()\n    ) {\n        Column(modifier = Modifier.padding(16.dp)) {\n            Text(\n                text = stringResource(R.string.manual_energy_title),\n                style = MaterialTheme.typography.titleMedium\n            )\n            \n            Text(\n                text = stringResource(R.string.manual_energy_subtitle),\n                style = MaterialTheme.typography.bodySmall,\n                color = MaterialTheme.colorScheme.onSurfaceVariant\n            )\n            \n            Spacer(modifier = Modifier.height(8.dp))\n            \n            Slider(\n                value = energyLevel.toFloat(),\n                onValueChange = { onEnergyChange(it.toInt()) },\n                valueRange = 1f..5f,\n                steps = 3\n            )\n            \n            Text(\n                text = stringResource(R.string.energy_level_label, energyLevel),\n                style = MaterialTheme.typography.bodyMedium,\n                modifier = Modifier.align(Alignment.CenterHorizontally)\n            )\n        }\n    }\n}\n\n